SELECT SUM(usage_amount) as total_energy_used
FROM usage_data
WHERE tariff_id = 1;

SELECT COUNT(*)
FROM billing_data
WHERE payment_status = 'unpaid';

SELECT account_id, SUM(bill_amount) AS total_bill_amount
FROM billing_data
GROUP BY account_id;

SELECT COUNT(DISTINCT bill_id) AS high_payment_bills
FROM payments
WHERE payment_amount > 100;

SELECT customers.name AS customer_name, utilities.utility_name
FROM customers
INNER JOIN utilities ON customers.utility_id = utilities.utility_id;

SELECT 
    (SELECT COUNT(DISTINCT customer_id) FROM customers) / 
    (SELECT COUNT(DISTINCT utility_id) FROM utilities) AS avg_customers_per_utility;
